mapper.select:
SELECT id, project_id, task_id, version_name, module_name, case_title, priority, case_type, precondition, steps, expected_result, test_data, source_chunk_ids, ai_score, review_status, deleted, created_at, updated_at FROM test_case WHERE project_id = #{projectId} AND deleted = false
AND version_name = #{versionName}
AND module_name = #{moduleName}
ORDER BY created_at DESC
